#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#define CPU_DELTA_REDUCE
#define CPU_CENTER_REDUCE

// Embedded Kernel Source
const char* kernel_source = 
"#ifndef _KMEANS_OPENCL_KERNEL_H_\n"
"#define _KMEANS_OPENCL_KERNEL_H_\n"
"#include <math.h>\n"
"#define ASSUMED_NR_CLUSTERS 32\n"
"#define THREADS_PER_DIM 16\n"
"#define THREADS_PER_BLOCK (THREADS_PER_DIM * THREADS_PER_DIM)\n"
"#ifndef FLT_MAX\n#define FLT_MAX 3.40282347e+38f\n#endif\n"
"#define GPU_DELTA_REDUCTION\n"
"#define GPU_NEW_CENTER_REDUCTION\n"
"__global__ void invert_mapping(const float *input, float *output, int npoints, int nfeatures) {\n"
"    int point_id = get_global_id(0);\n"
"    if(point_id < npoints){ for(int i=0;i<nfeatures;i++) output[point_id + npoints*i] = input[point_id*nfeatures + i]; }\n"
"}\n"
"__global__ void kmeansPoint(const float *features, int nfeatures, int npoints, int nclusters, int *membership, const float *clusters, float *block_clusters, int *block_deltas) {\n"
"    const unsigned int block_id = get_group_id(0);\n"
"    const unsigned int point_id = block_id * THREADS_PER_BLOCK + get_local_id(0);\n"
"    int index = -1;\n"
"    if (point_id < npoints) {\n"
"        float min_dist = FLT_MAX;\n"
"        for (int i=0; i<nclusters; i++) {\n"
"            float ans=0.0f;\n"
"            for (int j=0; j < nfeatures; j++) {\n"
"                float diff = features[point_id + j*npoints] - clusters[i*nfeatures + j];\n"
"                ans += diff*diff;\n"
"            }\n"
"            if (ans < min_dist) { min_dist = ans; index = i; }\n"
"        }\n"
"    }\n"
"    __local int deltas[THREADS_PER_BLOCK];\n"
"    if(get_local_id(0) < THREADS_PER_BLOCK) deltas[get_local_id(0)] = 0;\n"
"    if (point_id < npoints) { if (membership[point_id] != index) deltas[get_local_id(0)] = 1; membership[point_id] = index; }\n"
"    __syncthreads();\n"
"    unsigned int threadids_participating = THREADS_PER_BLOCK / 2;\n"
"    for(;threadids_participating > 1; threadids_participating /= 2) {\n"
"        if(get_local_id(0) < threadids_participating) deltas[get_local_id(0)] += deltas[get_local_id(0) + threadids_participating];\n"
"        __syncthreads();\n"
"    }\n"
"    if(get_local_id(0) < 1) deltas[get_local_id(0)] += deltas[get_local_id(0) + 1];\n"
"    __syncthreads();\n"
"    if(get_local_id(0) == 0) block_deltas[block_id] = deltas[0];\n"
"    int center_id = get_local_id(0) / nfeatures;\n"
"    int dim_id = get_local_id(0) - nfeatures*center_id;\n"
"    __local int new_center_ids[THREADS_PER_BLOCK];\n"
"    new_center_ids[get_local_id(0)] = index;\n"
"    __syncthreads();\n"
"    int new_base_index = (point_id - get_local_id(0))*nfeatures + dim_id;\n"
"    float accumulator = 0.0f;\n"
"    if(get_local_id(0) < nfeatures * nclusters) {\n"
"        for(int i = 0; i< THREADS_PER_BLOCK; i++) {\n"
"            int idx = new_base_index + i*nfeatures;\n"
"            if (idx < npoints * nfeatures && new_center_ids[i] == center_id) accumulator += features[idx];\n"
"        }\n"
"        block_clusters[block_id * nclusters * nfeatures + get_local_id(0)] = accumulator;\n"
"    }\n"
"}\n"
"#endif\n";

extern "C"
int setup(int argc, char** argv);

unsigned int num_threads_perdim = THREADS_PER_DIM;
unsigned int num_blocks_perdim = BLOCKS_PER_DIM;
unsigned int num_threads = num_threads_perdim*num_threads_perdim;
unsigned int num_blocks = num_blocks_perdim*num_blocks_perdim;

int    *membership_new;
float  *feature_d;
float  *feature_flipped_d;
int    *membership_d;
float  *block_new_centers;
float  *clusters_d;
float  *block_clusters_d;
int    *block_deltas_d;

// OpenCL globals
cl_context context;
cl_device_id device;
cl_command_queue queue;
cl_program program;
cl_kernel kernel_invert;
cl_kernel kernel_kmeans;

extern "C"
void allocateMemory(int npoints, int nfeatures, int nclusters, float **features)
{
    cl_int err;
    num_blocks = npoints / num_threads;
    if (npoints % num_threads > 0) num_blocks++;
    num_blocks_perdim = sqrt((double) num_blocks);
    while (num_blocks_perdim * num_blocks_perdim < num_blocks) num_blocks_perdim++;
    num_blocks = num_blocks_perdim*num_blocks_perdim;

    membership_new = (int*) malloc(npoints * sizeof(int));
    for(int i=0;i<npoints;i++) membership_new[i] = -1;
    block_new_centers = (float *) malloc(nclusters*nfeatures*sizeof(float));

    // Init OpenCL
    cl_platform_id platform;
    clGetPlatformIDs(1, &platform, NULL);
    clGetDeviceIDs(platform, CL_DEVICE_TYPE_GPU, 1, &device, NULL);
    context = clCreateContext(NULL, 1, &device, NULL, NULL, &err);
    queue = clCreateCommandQueue(context, device, 0, &err);

    // Create Program
    program = clCreateProgramWithSource(context, 1, &kernel_source, NULL, &err);
    char options[256];
    sprintf(options, "-DTHREADS_PER_DIM=%d -DASSUMED_NR_CLUSTERS=%d", THREADS_PER_DIM, ASSUMED_NR_CLUSTERS);
    clBuildProgram(program, 1, &device, options, NULL, NULL);

    kernel_invert = clCreateKernel(program, "invert_mapping", &err);
    kernel_kmeans = clCreateKernel(program, "kmeansPoint", &err);

    // Allocate Buffers
    feature_flipped_d = (float*)clCreateBuffer(context, CL_MEM_READ_WRITE, npoints*nfeatures*sizeof(float), NULL, &err);
    clEnqueueWriteBuffer(queue, feature_flipped_d, CL_TRUE, 0, npoints*nfeatures*sizeof(float), features[0], 0, NULL, NULL);

    feature_d = (float*)clCreateBuffer(context, CL_MEM_READ_WRITE, npoints*nfeatures*sizeof(float), NULL, &err);

    size_t global_inv = num_blocks * num_threads;
    clSetKernelArg(kernel_invert, 0, sizeof(cl_mem), &feature_flipped_d);
    clSetKernelArg(kernel_invert, 1, sizeof(cl_mem), &feature_d);
    clSetKernelArg(kernel_invert, 2, sizeof(int), &npoints);
    clSetKernelArg(kernel_invert, 3, sizeof(int), &nfeatures);
    clEnqueueTaskKernel(queue, kernel_invert, 1, &global_inv, NULL, NULL); // Simplified launch

    membership_d = (int*)clCreateBuffer(context, CL_MEM_READ_WRITE, npoints*sizeof(int), NULL, &err);
    clusters_d = (float*)clCreateBuffer(context, CL_MEM_READ_WRITE, nclusters*nfeatures*sizeof(float), NULL, &err);

#ifdef BLOCK_DELTA_REDUCE
    block_deltas_d = (int*)clCreateBuffer(context, CL_MEM_READ_WRITE, num_blocks*sizeof(int), NULL, &err);
#endif
#ifdef BLOCK_CENTER_REDUCE
    block_clusters_d = (float*)clCreateBuffer(context, CL_MEM_READ_WRITE, num_blocks*nclusters*nfeatures*sizeof(float), NULL, &err);
#endif
}

extern "C"
void deallocateMemory()
{
    free(membership_new);
    free(block_new_centers);
    clReleaseMemObject((cl_mem)feature_d);
    clReleaseMemObject((cl_mem)feature_flipped_d);
    clReleaseMemObject((cl_mem)membership_d);
    clReleaseMemObject((cl_mem)clusters_d);
#ifdef BLOCK_CENTER_REDUCE
    clReleaseMemObject((cl_mem)block_clusters_d);
#endif
#ifdef BLOCK_DELTA_REDUCE
    clReleaseMemObject((cl_mem)block_deltas_d);
#endif
    clReleaseKernel(kernel_invert);
    clReleaseKernel(kernel_kmeans);
    clReleaseProgram(program);
    clReleaseCommandQueue(queue);
    clReleaseContext(context);
}

int main(int argc, char** argv) 
{
    setup(argc, argv);    
    return 0;
}

extern "C"
int kmeansCuda(float  **feature,
           int      nfeatures,
           int      npoints,
           int      nclusters,
           int     *membership,
           float  **clusters,
           int     *new_centers_len,
           float  **new_centers)
{
    int delta = 0;
    int i,j;
    cl_int err;

    clEnqueueWriteBuffer(queue, (cl_mem)membership_d, CL_TRUE, 0, npoints*sizeof(int), membership_new, 0, NULL, NULL);
    clEnqueueWriteBuffer(queue, (cl_mem)clusters_d, CL_TRUE, 0, nclusters*nfeatures*sizeof(float), clusters[0], 0, NULL, NULL);

    size_t global_size = num_blocks * num_threads;
    size_t local_size = num_threads;

    clSetKernelArg(kernel_kmeans, 0, sizeof(cl_mem), &feature_d);
    clSetKernelArg(kernel_kmeans, 1, sizeof(int), &nfeatures);
    clSetKernelArg(kernel_kmeans, 2, sizeof(int), &npoints);
    clSetKernelArg(kernel_kmeans, 3, sizeof(int), &nclusters);
    clSetKernelArg(kernel_kmeans, 4, sizeof(cl_mem), &membership_d);
    clSetKernelArg(kernel_kmeans, 5, sizeof(cl_mem), &clusters_d);
    clSetKernelArg(kernel_kmeans, 6, sizeof(cl_mem), &block_clusters_d);
    clSetKernelArg(kernel_kmeans, 7, sizeof(cl_mem), &block_deltas_d);

    clEnqueueTaskKernel(queue, kernel_kmeans, 1, &global_size, &local_size, NULL, NULL);
    clFinish(queue);

    clEnqueueReadBuffer(queue, (cl_mem)membership_d, CL_TRUE, 0, npoints*sizeof(int), membership_new, 0, NULL, NULL);

#ifdef BLOCK_CENTER_REDUCE
    float * block_clusters_h = (float *) malloc(num_blocks * nclusters * nfeatures * sizeof(float));
    clEnqueueReadBuffer(queue, (cl_mem)block_clusters_d, CL_TRUE, 0, num_blocks * nclusters * nfeatures * sizeof(float), block_clusters_h, 0, NULL, NULL);
#endif
#ifdef BLOCK_DELTA_REDUCE
    int * block_deltas_h = (int *) malloc(num_blocks * sizeof(int));
    clEnqueueReadBuffer(queue, (cl_mem)block_deltas_d, CL_TRUE, 0, num_blocks * sizeof(int), block_deltas_h, 0, NULL, NULL);
#endif

    delta = 0;
    for (i = 0; i < npoints; i++)
    {
        int cluster_id = membership_new[i];
        new_centers_len[cluster_id]++;
        if (membership_new[i] != membership[i])
        {
#ifdef CPU_DELTA_REDUCE
            delta++;
#endif
            membership[i] = membership_new[i];
        }
#ifdef CPU_CENTER_REDUCE
        for (j = 0; j < nfeatures; j)
        {
            new_centers[cluster_id][j] += feature[i][j];
        }
#endif
    }

#ifdef BLOCK_DELTA_REDUCE
    for(i = 0; i < num_blocks; i++) delta += block_deltas_h[i];
    free(block_deltas_h);
#endif
#ifdef BLOCK_CENTER_REDUCE
    for(int j = 0; j < nclusters;j++) {
        for(int k = 0; k < nfeatures;k++) block_new_centers[j*nfeatures + k] = 0.f;
    }
    for(i = 0; i < num_blocks; i++) {
        for(int j = 0; j < nclusters;j++) {
            for(int k = 0; k < nfeatures;k++) {
                block_new_centers[j*nfeatures + k] += block_clusters_h[i * nclusters*nfeatures + j * nfeatures + k];
            }
        }
    }
    for(int j = 0; j < nclusters;j++) {
        for(int k = 0; k < nfeatures;k++)
            new_centers[j][k]= block_new_centers[j*nfeatures + k];
    }
    free(block_clusters_h);
#endif

    return delta;
}
